  ('jee-physics-optics-q05', 'jee-physics-optics', 'Snell''s law relates the angles of incidence and refraction through:', 'n1 cos(i) = n2 cos(r)', 'n1 tan(i) = n2 tan(r)', 'n1 i = n2 r', 'n1 sin(i) = n2 sin(r)', 'D', 'Snell''s law: n1 sin(i) = n2 sin(r).', 4),
  ('jee-physics-optics-q06', 'jee-physics-optics', 'For constructive interference, the path difference must be:', 'An odd multiple of lambda/2', 'lambda/4', 'An integer multiple of lambda', 'Zero only', 'C', 'Bright fringes appear where the path difference equals n times lambda.', 5),
  ('jee-physics-optics-q07', 'jee-physics-optics', 'When unpolarised light passes through two polarisers, Malus''s law gives the transmitted intensity as:', 'I0', 'I0 cos(theta)', 'I0 sin²(theta)', 'I0 cos²(theta)', 'D', 'Malus''s law: I = I0 cos²(theta) for polarised light through an analyser.', 6),
  ('jee-physics-optics-q08', 'jee-physics-optics', 'A convex lens of focal length 10 cm forms an image of an object at 20 cm. The image distance is:', '40 cm', '10 cm', '5 cm', '20 cm', 'D', '1/v - 1/u = 1/f gives 1/v = 1/10 - 1/20, so v = 20 cm.', 7),
  ('jee-physics-modern-physics-q01', 'jee-physics-modern-physics', 'In the photoelectric effect, increasing the light intensity (frequency fixed) increases:', 'Work function', 'Maximum kinetic energy', 'Threshold frequency', 'Number of emitted electrons', 'D', 'Higher intensity means more photons, hence more electrons, but the same maximum KE.', 0),
  ('jee-physics-modern-physics-q02', 'jee-physics-modern-physics', 'The energy of the ground state of the hydrogen atom is:', '-3.4 eV', '-1.51 eV', '-13.6 eV', '0 eV', 'C', 'The n = 1 level of hydrogen has energy -13.6 eV.', 1),
  ('jee-physics-modern-physics-q03', 'jee-physics-modern-physics', 'The de Broglie wavelength of a particle of momentum p is:', 'h / p', 'h / p²', 'p / h', 'h p', 'A', 'de Broglie wavelength lambda = h/p.', 2),
  ('jee-physics-modern-physics-q04', 'jee-physics-modern-physics', 'A radioactive sample has a half-life of 5 years. After 15 years the fraction remaining is:', '1/4', '1/8', '1/2', '1/16', 'B', '15 years is three half-lives, leaving (1/2)³ = 1/8 of the sample.', 3),
  ('jee-physics-modern-physics-q05', 'jee-physics-modern-physics', 'Einstein''s photoelectric equation is KE_max =:', 'hf + phi', 'phi - hf', 'hf - phi', 'hf x phi', 'C', 'KE_max = hf - phi, where phi is the work function.', 4),
  ('jee-physics-modern-physics-q06', 'jee-physics-modern-physics', 'Emission of an alpha particle reduces the mass number of a nucleus by:', '1', '4', '2', '0', 'B', 'An alpha particle is a helium nucleus, so mass number drops by 4.', 5),
  ('jee-physics-modern-physics-q07', 'jee-physics-modern-physics', 'The relation between energy and mass defect is given by:', 'E = mc²', 'E = mc', 'E = m/c²', 'E = m²c', 'A', 'Einstein''s mass-energy relation E = mc² gives the released binding energy.', 6),
  ('jee-physics-modern-physics-q08', 'jee-physics-modern-physics', 'The radius of the n-th Bohr orbit varies with n as:', 'n', '1/n²', '1/n', 'n²', 'D', 'The Bohr radius r_n is proportional to n².', 7),
  ('jee-physics-thermodynamics-q01', 'jee-physics-thermodynamics', 'The first law of thermodynamics is a statement of conservation of:', 'Mass', 'Momentum', 'Energy', 'Charge', 'C', 'The first law, delta U = Q - W, expresses conservation of energy.', 0),
  ('jee-physics-thermodynamics-q02', 'jee-physics-thermodynamics', 'In an isothermal process for an ideal gas, the change in internal energy is:', 'Negative', 'Zero', 'Positive', 'Equal to the work done', 'B', 'Internal energy depends on temperature only; at constant T, delta U = 0.', 1),
  ('jee-physics-thermodynamics-q03', 'jee-physics-thermodynamics', 'In an adiabatic process the quantity that stays constant is:', 'Heat exchanged Q', 'Pressure', 'Temperature', 'Volume', 'A', 'An adiabatic process has Q = 0, with no heat exchanged.', 2),
  ('jee-physics-thermodynamics-q04', 'jee-physics-thermodynamics', 'The efficiency of a Carnot engine between 600 K and 300 K is:', '25 percent', '75 percent', '50 percent', '100 percent', 'C', 'eta = 1 - T_cold/T_hot = 1 - 300/600 = 0.5, or 50 percent.', 3),
  ('jee-physics-thermodynamics-q05', 'jee-physics-thermodynamics', 'The work done in an isochoric (constant volume) process is:', 'Zero', 'Maximum', 'P delta V', 'nRT', 'A', 'With no volume change, W = P delta V = 0.', 4),
