  ('jee-chemistry-periodicity-q08', 'jee-chemistry-periodicity', 'Down a group, metallic character generally:', 'Decreases', 'Increases', 'Stays constant', 'Disappears', 'B', 'Easier electron loss down a group increases metallic character.', 7),
  ('jee-chemistry-mole-concept-q01', 'jee-chemistry-mole-concept', 'The number of molecules in 2 moles of a gas is:', '6.022 x 10^23', '12 x 10^24', '1.2 x 10^24', '3.0 x 10^23', 'C', '2 moles contain 2 x 6.022 x 10^23 = 1.2 x 10^24 molecules.', 0),
  ('jee-chemistry-mole-concept-q02', 'jee-chemistry-mole-concept', 'The molar volume of an ideal gas at STP is:', '22.4 L', '11.2 L', '24.4 L', '1 L', 'A', 'One mole of ideal gas occupies 22.4 L at STP.', 1),
  ('jee-chemistry-mole-concept-q03', 'jee-chemistry-mole-concept', 'The number of moles in 36 g of water (molar mass 18) is:', '2', '1', '0.5', '18', 'A', 'moles = mass/molar mass = 36/18 = 2.', 2),
  ('jee-chemistry-mole-concept-q04', 'jee-chemistry-mole-concept', 'Molarity is defined as moles of solute per:', 'Kilogram of solvent', 'Litre of solution', 'Litre of solvent', 'Mole of solution', 'B', 'Molarity = moles of solute per litre of solution.', 3),
  ('jee-chemistry-mole-concept-q05', 'jee-chemistry-mole-concept', 'In a reaction, the reagent that is completely consumed is called the:', 'Excess reagent', 'Product', 'Catalyst', 'Limiting reagent', 'D', 'The limiting reagent runs out first and caps the amount of product.', 4),
  ('jee-chemistry-mole-concept-q06', 'jee-chemistry-mole-concept', 'The mass of 0.5 mole of CO2 (molar mass 44) is:', '22 g', '11 g', '44 g', '88 g', 'A', 'mass = moles x molar mass = 0.5 x 44 = 22 g.', 5),
  ('jee-chemistry-mole-concept-q07', 'jee-chemistry-mole-concept', 'On dilution of a solution, the number of moles of solute:', 'Increases', 'Becomes zero', 'Decreases', 'Stays the same', 'D', 'Dilution adds only solvent, so moles of solute stay constant (M1V1 = M2V2).', 6),
  ('jee-chemistry-mole-concept-q08', 'jee-chemistry-mole-concept', 'The empirical formula of a compound with 40 percent C, 6.7 percent H and 53.3 percent O (by mass) is:', 'CHO', 'CH4O', 'C2H4O2', 'CH2O', 'D', 'Mole ratio C:H:O is about 1:2:1, giving the empirical formula CH2O.', 7),
  ('jee-chemistry-equilibrium-q01', 'jee-chemistry-equilibrium', 'At chemical equilibrium, the rates of the forward and reverse reactions are:', 'Equal', 'Maximum', 'Zero', 'Unrelated', 'A', 'Equilibrium is dynamic: forward and reverse rates are equal.', 0),
  ('jee-chemistry-equilibrium-q02', 'jee-chemistry-equilibrium', 'The pH of a 0.01 M strong acid solution is:', '1', '2', '12', '0.01', 'B', 'pH = -log(0.01) = 2.', 1),
  ('jee-chemistry-equilibrium-q03', 'jee-chemistry-equilibrium', 'Adding more reactant to a system at equilibrium shifts it, by Le Chatelier, toward the:', 'Reactants', 'Products', 'No change', 'Solid phase', 'B', 'Increasing a reactant drives the equilibrium toward the products.', 2),
  ('jee-chemistry-equilibrium-q04', 'jee-chemistry-equilibrium', 'The ionic product of water Kw at 25 C is:', '10^-7', '10^-14', '10^-1', '1', 'B', 'Kw = [H+][OH-] = 1.0 x 10^-14 at 25 C.', 3),
  ('jee-chemistry-equilibrium-q05', 'jee-chemistry-equilibrium', 'Increasing pressure on a gaseous equilibrium shifts it toward the side with:', 'Higher temperature', 'More gas moles', 'Fewer gas moles', 'More solid', 'C', 'Higher pressure favours the side with fewer moles of gas.', 4),
  ('jee-chemistry-equilibrium-q06', 'jee-chemistry-equilibrium', 'A buffer solution is best described as one that resists changes in:', 'Temperature', 'Volume', 'Colour', 'pH', 'D', 'A buffer resists pH change on adding small amounts of acid or base.', 5),
  ('jee-chemistry-equilibrium-q07', 'jee-chemistry-equilibrium', 'The relation between Kp and Kc is Kp =:', 'Kc + RT', 'Kc / RT', 'Kc (RT)^delta-n', 'Kc x RT', 'C', 'Kp = Kc (RT) raised to the change in moles of gas, delta-n.', 6),
  ('jee-chemistry-equilibrium-q08', 'jee-chemistry-equilibrium', 'Adding a common ion to a weak electrolyte solution:', 'Increases its ionisation', 'Changes its identity', 'Has no effect', 'Suppresses its ionisation', 'D', 'The common-ion effect shifts equilibrium back, suppressing ionisation.', 7),
  ('jee-chemistry-thermodynamics-q01', 'jee-chemistry-thermodynamics', 'A reaction is spontaneous when the Gibbs energy change is:', 'Positive', 'Negative', 'Zero', 'Infinite', 'B', 'Spontaneity requires delta G to be negative.', 0),
  ('jee-chemistry-thermodynamics-q02', 'jee-chemistry-thermodynamics', 'Hess''s law is based on the fact that enthalpy is a:', 'Path function', 'State function', 'Random variable', 'Constant for all reactions', 'B', 'Enthalpy is a state function, so delta H is path-independent.', 1),
  ('jee-chemistry-thermodynamics-q03', 'jee-chemistry-thermodynamics', 'The Gibbs energy relation is delta G =:', 'delta H + T delta S', 'T delta S - delta H', 'delta H - T delta S', 'delta H x T delta S', 'C', 'delta G = delta H - T delta S.', 2),
  ('jee-chemistry-thermodynamics-q04', 'jee-chemistry-thermodynamics', 'For an exothermic reaction, the enthalpy change delta H is:', 'Positive', 'Zero', 'Always one', 'Negative', 'D', 'Exothermic reactions release heat, so delta H is negative.', 3),
  ('jee-chemistry-thermodynamics-q05', 'jee-chemistry-thermodynamics', 'The entropy of a perfect crystal at absolute zero is, by the third law:', 'Zero', 'Maximum', 'Negative', 'Undefined', 'A', 'The third law sets the entropy of a perfect crystal at 0 K to zero.', 4),
  ('jee-chemistry-thermodynamics-q06', 'jee-chemistry-thermodynamics', 'At equilibrium, the Gibbs energy change of a reaction is:', 'Maximum', 'Zero', 'Minimum negative', 'Large positive', 'B', 'At equilibrium delta G = 0.', 5),
  ('jee-chemistry-thermodynamics-q07', 'jee-chemistry-thermodynamics', 'The relation between standard Gibbs energy and equilibrium constant is delta G-standard =:', '-RT ln K', 'RT ln K', '-R/T ln K', 'RT/K', 'A', 'delta G-standard = -RT ln K links thermodynamics to equilibrium.', 6),
  ('jee-chemistry-thermodynamics-q08', 'jee-chemistry-thermodynamics', 'Which reaction generally shows a positive entropy change?', 'Solid to gas', 'Liquid to solid', 'Gas to liquid', 'Two gases combining into one', 'A', 'Sublimation increases disorder, giving a positive entropy change.', 7),
  ('jee-chemistry-goc-q01', 'jee-chemistry-goc', 'The stability order of carbocations is:', 'methyl > 1 degree > 2 degree > 3 degree', 'All equally stable', '3 degree > 2 degree > 1 degree > methyl', '1 degree > 2 degree > 3 degree', 'C', 'Tertiary carbocations are most stable due to hyperconjugation and inductive donation.', 0),
  ('jee-chemistry-goc-q02', 'jee-chemistry-goc', 'An electron-deficient species that seeks electrons is a:', 'Nucleophile', 'Free radical', 'Electrophile', 'Carbanion', 'C', 'Electrophiles are electron-poor and accept electron pairs.', 1),
  ('jee-chemistry-goc-q03', 'jee-chemistry-goc', 'The -NO2 group exerts which kind of inductive effect?', 'Electron-withdrawing (-I)', 'Electron-donating (+I)', 'No effect', 'Only resonance', 'A', 'Nitro is strongly electron-withdrawing, showing a -I effect.', 2),
  ('jee-chemistry-goc-q04', 'jee-chemistry-goc', 'A carbon atom bonded to four different groups is called:', 'Quaternary', 'Primary', 'Aromatic', 'Chiral', 'D', 'A chiral (asymmetric) carbon has four different substituents and is optically active.', 3),
  ('jee-chemistry-goc-q05', 'jee-chemistry-goc', 'Which is the strongest acid among the following?', 'Ethanol', 'Acetic acid', 'Phenol', 'Water', 'B', 'Carboxylic acids are stronger than phenols and alcohols due to resonance-stabilised anions.', 4),
  ('jee-chemistry-goc-q06', 'jee-chemistry-goc', 'Hyperconjugation involves the delocalisation of electrons from:', 'Lone pairs', 'pi to pi bonds', 'd orbitals', 'Adjacent C-H sigma bonds', 'D', 'Hyperconjugation delocalises electrons of neighbouring C-H sigma bonds into an empty or pi orbital.', 5),
  ('jee-chemistry-goc-q07', 'jee-chemistry-goc', 'Compounds with the same molecular formula but different structures are called:', 'Isotopes', 'Homologues', 'Allotropes', 'Isomers', 'D', 'Isomers share a molecular formula but differ in structure or arrangement.', 6),
  ('jee-chemistry-goc-q08', 'jee-chemistry-goc', 'The resonance (+M) effect of -OH on benzene makes the ring:', 'Deactivated', 'Inert', 'Meta-directing', 'Activated toward electrophiles', 'D', '-OH donates electrons by resonance, activating the ring and directing ortho/para.', 7),
  ('jee-chemistry-hydrocarbons-q01', 'jee-chemistry-hydrocarbons', 'The general formula of an alkane is:', 'CnHn', 'CnH2n', 'CnH2n-2', 'CnH2n+2', 'D', 'Saturated open-chain alkanes follow CnH2n+2.', 0),
  ('jee-chemistry-hydrocarbons-q02', 'jee-chemistry-hydrocarbons', 'Alkanes typically undergo which kind of reaction with halogens in sunlight?', 'Electrophilic addition', 'Free-radical substitution', 'Nucleophilic substitution', 'Elimination', 'B', 'Alkanes undergo free-radical substitution with halogens under UV light.', 1),
  ('jee-chemistry-hydrocarbons-q03', 'jee-chemistry-hydrocarbons', 'Markovnikov''s rule predicts the addition of HBr to propene gives mainly:', 'Propane', '1-bromopropane', '2-bromopropane', 'Propyne', 'C', 'H adds to the carbon with more hydrogens, putting Br on C2 (2-bromopropane).', 2),
  ('jee-chemistry-hydrocarbons-q04', 'jee-chemistry-hydrocarbons', 'Benzene preferentially undergoes:', 'Free-radical addition', 'Addition reactions', 'Nucleophilic addition', 'Electrophilic substitution', 'D', 'Aromatic stability makes benzene favour electrophilic substitution over addition.', 3),
  ('jee-chemistry-hydrocarbons-q05', 'jee-chemistry-hydrocarbons', 'The number of pi bonds in an alkyne triple bond is:', '0', '2', '3', '1', 'B', 'A triple bond has one sigma and two pi bonds.', 4),
  ('jee-chemistry-hydrocarbons-q06', 'jee-chemistry-hydrocarbons', 'Aromaticity by Huckel''s rule requires the number of pi electrons to equal:', '4n + 2', '2n', '4n', 'n + 1', 'A', 'Huckel''s rule: a planar cyclic system is aromatic with (4n + 2) pi electrons.', 5),
  ('jee-chemistry-hydrocarbons-q07', 'jee-chemistry-hydrocarbons', 'Addition of HBr to an alkene in the presence of peroxide gives anti-Markovnikov product via:', 'Carbocation mechanism', 'Ionic mechanism', 'Free-radical mechanism', 'No reaction', 'C', 'The peroxide effect proceeds by a free-radical chain, reversing the regiochemistry.', 6),
  ('jee-chemistry-hydrocarbons-q08', 'jee-chemistry-hydrocarbons', 'A -NO2 substituent on benzene directs an incoming electrophile to the:', 'Meta position', 'Para position', 'Ortho position', 'Ipso position', 'A', 'Nitro is a deactivating, meta-directing group.', 7),
  ('jee-chemistry-coordination-compounds-q01', 'jee-chemistry-coordination-compounds', 'The coordination number of the central metal in [Co(NH3)6]3+ is:', '6', '4', '3', '2', 'A', 'Six ammonia ligands give a coordination number of 6.', 0),
  ('jee-chemistry-coordination-compounds-q02', 'jee-chemistry-coordination-compounds', 'A ligand that binds through two donor atoms is called:', 'Monodentate', 'Ambidentate', 'Bidentate', 'Neutral', 'C', 'A bidentate ligand, such as ethylenediamine, donates through two atoms.', 1),
  ('jee-chemistry-coordination-compounds-q03', 'jee-chemistry-coordination-compounds', 'In crystal field theory, ligands split the d orbitals into:', 't2g and eg sets', 's and p sets', 'Two equal halves', 'Three triplets', 'A', 'In an octahedral field, the d orbitals split into lower t2g and higher eg sets.', 2),
  ('jee-chemistry-coordination-compounds-q04', 'jee-chemistry-coordination-compounds', 'Which ligand is a strong-field ligand that favours low-spin complexes?', 'I-', 'Br-', 'CN-', 'Cl-', 'C', 'Cyanide is a strong-field ligand causing large splitting and low-spin pairing.', 3),
  ('jee-chemistry-coordination-compounds-q05', 'jee-chemistry-coordination-compounds', 'The spin-only magnetic moment for a complex with 2 unpaired electrons is about:', '1.73 BM', '0 BM', '3.87 BM', '2.83 BM', 'D', 'mu = sqrt(n(n+2)) = sqrt(8) = 2.83 BM for n = 2.', 4),
  ('jee-chemistry-coordination-compounds-q06', 'jee-chemistry-coordination-compounds', 'cis-trans isomerism in coordination compounds is a type of:', 'Ionisation isomerism', 'Optical isomerism', 'Geometrical isomerism', 'Linkage isomerism', 'C', 'cis and trans arrangements of ligands are geometrical isomers.', 5),
  ('jee-chemistry-coordination-compounds-q07', 'jee-chemistry-coordination-compounds', 'A polydentate ligand forming a ring with the metal is said to produce a:', 'Lattice', 'Chelate', 'Salt bridge', 'Polymer', 'B', 'Ring formation by a polydentate ligand is called chelation, giving a chelate.', 6),
  ('jee-chemistry-coordination-compounds-q08', 'jee-chemistry-coordination-compounds', 'In the spectrochemical series, which ligand causes the largest crystal-field splitting?', 'H2O', 'CO', 'NH3', 'Cl-', 'B', 'CO lies highest in the spectrochemical series, producing the largest splitting.', 7),
  ('jee-chemistry-electrochemistry-q01', 'jee-chemistry-electrochemistry', 'In a galvanic cell, oxidation occurs at the:', 'Anode', 'Salt bridge', 'Cathode', 'Electrolyte', 'A', 'Oxidation always occurs at the anode of any electrochemical cell.', 0),
  ('jee-chemistry-electrochemistry-q02', 'jee-chemistry-electrochemistry', 'The value of the Faraday constant is approximately:', '9650 C/mol', '96500 C/mol', '6.022 x 10^23 C/mol', '1.6 x 10^-19 C/mol', 'B', 'One Faraday is about 96500 C, the charge of one mole of electrons.', 1),
  ('jee-chemistry-electrochemistry-q03', 'jee-chemistry-electrochemistry', 'The standard cell potential is given by E-cathode minus:', 'Zero', 'E-anode', 'E-electrolyte', 'Twice E-anode', 'B', 'E-cell-standard = E-cathode-standard minus E-anode-standard.', 2),
  ('jee-chemistry-electrochemistry-q04', 'jee-chemistry-electrochemistry', 'The Nernst equation introduces a correction term proportional to:', '1/Q', 'Q squared', 'exp(Q)', 'log Q', 'D', 'The Nernst equation subtracts (0.059/n) log Q from the standard potential.', 3),
  ('jee-chemistry-electrochemistry-q05', 'jee-chemistry-electrochemistry', 'A positive standard reduction potential indicates a species that is a:', 'Strong oxidising agent', 'Poor conductor', 'Neutral species', 'Strong reducing agent', 'A', 'More positive reduction potential means a stronger tendency to be reduced, a good oxidiser.', 4),
  ('jee-chemistry-electrochemistry-q06', 'jee-chemistry-electrochemistry', 'The relation between Gibbs energy and cell potential is delta G-standard =:', 'nFE-standard', 'nF / E-standard', '-nFE-standard', 'E-standard / nF', 'C', 'delta G-standard = -nFE-cell-standard.', 5),
  ('jee-chemistry-electrochemistry-q07', 'jee-chemistry-electrochemistry', 'Kohlrausch''s law concerns the molar conductivity at:', 'Infinite dilution', 'Freezing point', 'Standard pressure', 'High concentration', 'A', 'Kohlrausch''s law gives molar conductivity at infinite dilution as a sum of ionic contributions.', 6),
  ('jee-chemistry-electrochemistry-q08', 'jee-chemistry-electrochemistry', 'Passing 96500 C through molten NaCl deposits how many gram-equivalents of sodium?', '1', '0.5', '2', '23', 'A', 'By Faraday''s law, 96500 C deposits one gram-equivalent of the element.', 7),
