  ('jee-mathematics-sequences-series-q01', 'jee-mathematics-sequences-series', 'The 10th term of the AP 2, 5, 8, ... is:', '27', '29', '30', '32', 'B', 'a_n = a + (n-1)d = 2 + 9(3) = 29.', 0),
  ('jee-mathematics-sequences-series-q02', 'jee-mathematics-sequences-series', 'The sum of the first n natural numbers is:', 'n(n+1)', 'n(n+1)/2', 'n²', 'n(2n+1)/6', 'B', 'Sum of first n naturals is n(n+1)/2.', 1),
  ('jee-mathematics-sequences-series-q03', 'jee-mathematics-sequences-series', 'The sum of an infinite GP with first term 1 and ratio 1/2 is:', 'Infinite', '1', '1.5', '2', 'D', 'S = a/(1 - r) = 1/(1 - 0.5) = 2.', 2),
  ('jee-mathematics-sequences-series-q04', 'jee-mathematics-sequences-series', 'The geometric mean of 4 and 9 is:', '13', '6.5', '6', '36', 'C', 'GM = sqrt(4 x 9) = sqrt(36) = 6.', 3),
  ('jee-mathematics-sequences-series-q05', 'jee-mathematics-sequences-series', 'For positive numbers, the relation among the three means is:', 'AM = GM = HM', 'AM is at least GM is at least HM', 'HM is at least GM is at least AM', 'GM is the largest', 'B', 'AM is greater than or equal to GM, which is greater than or equal to HM.', 4),
  ('jee-mathematics-sequences-series-q06', 'jee-mathematics-sequences-series', 'The 5th term of the GP 3, 6, 12, ... is:', '24', '96', '36', '48', 'D', 'a_n = a r^(n-1) = 3 x 2^4 = 48.', 5),
  ('jee-mathematics-sequences-series-q07', 'jee-mathematics-sequences-series', 'The sum of squares of the first n natural numbers is:', 'n(n+1)/2', 'n(n+1)(2n+1)/6', '[n(n+1)/2]²', 'n²', 'B', 'Sum of squares is n(n+1)(2n+1)/6.', 6),
  ('jee-mathematics-sequences-series-q08', 'jee-mathematics-sequences-series', 'A sequence whose reciprocals form an AP is called a:', 'Geometric progression', 'Fibonacci sequence', 'Arithmetic progression', 'Harmonic progression', 'D', 'If reciprocals are in AP, the original sequence is a harmonic progression.', 7),
  ('jee-mathematics-permutations-combinations-q01', 'jee-mathematics-permutations-combinations', 'The value of 5! (5 factorial) is:', '25', '720', '60', '120', 'D', '5! = 5 x 4 x 3 x 2 x 1 = 120.', 0),
  ('jee-mathematics-permutations-combinations-q02', 'jee-mathematics-permutations-combinations', 'The number of ways to choose 2 items from 5 distinct items is:', '5', '25', '10', '20', 'C', '5C2 = 10.', 1),
  ('jee-mathematics-permutations-combinations-q03', 'jee-mathematics-permutations-combinations', 'The number of arrangements (permutations) of 3 items chosen from 5 is:', '15', '60', '120', '10', 'B', '5P3 = 5!/(2!) = 60.', 2),
  ('jee-mathematics-permutations-combinations-q04', 'jee-mathematics-permutations-combinations', 'The number of circular permutations of 5 distinct objects is:', '5', '120', '24', '60', 'C', 'Circular permutations of n objects equal (n-1)! = 4! = 24.', 3),
  ('jee-mathematics-permutations-combinations-q05', 'jee-mathematics-permutations-combinations', 'The sum of all binomial coefficients nC0 + nC1 + ... + nCn equals:', 'n', 'n squared', 'n!', '2 raised to n', 'D', 'Setting a = b = 1 in (a+b)^n gives the sum 2 raised to n.', 4),
