  ('jee-mathematics-permutations-combinations-q07', 'jee-mathematics-permutations-combinations', 'The identity nCr equals:', 'nC(n+r)', 'nCr-1', 'n!/r!', 'nC(n-r)', 'D', 'By symmetry, nCr = nC(n-r).', 6),
  ('jee-mathematics-permutations-combinations-q08', 'jee-mathematics-permutations-combinations', 'The number of ways to select at least one item from 4 distinct items is:', '4', '8', '15', '16', 'C', 'Total subsets minus the empty set: 2^4 - 1 = 15.', 7),
  ('jee-mathematics-binomial-theorem-q01', 'jee-mathematics-binomial-theorem', 'The number of terms in the expansion of (a + b) raised to 7 is:', '7', '14', '9', '8', 'D', 'The expansion of (a + b)^n has n + 1 terms, here 8.', 0),
  ('jee-mathematics-binomial-theorem-q02', 'jee-mathematics-binomial-theorem', 'The general term of (a + b) raised to n is:', 'nCr a^r b^(n-r)', 'nCr a^(n-r) b^r', 'nPr a^(n-r) b^r', 'a^(n-r) b^r', 'B', 'The (r+1)th term is nCr times a^(n-r) times b^r.', 1),
  ('jee-mathematics-binomial-theorem-q03', 'jee-mathematics-binomial-theorem', 'The coefficient of x² in the expansion of (1 + x) raised to 4 is:', '12', '4', '8', '6', 'D', 'The coefficient is 4C2 = 6.', 2),
