  ('jee-mathematics-binomial-theorem-q05', 'jee-mathematics-binomial-theorem', 'The sum of the binomial coefficients in (1 + x) raised to 5 is:', '16', '32', '10', '25', 'B', 'Putting x = 1 gives 2^5 = 32.', 4),
