  ('ssc-cgl-general-awareness-books-authors-awards-q08', 'ssc-cgl-general-awareness-books-authors-awards', 'Which civilian award ranks higher?', 'Padma Shri', 'Padma Bhushan', 'Padma Vibhushan', 'They are equal', 'C', 'Order is Bharat Ratna > Padma Vibhushan > Padma Bhushan > Padma Shri.', 7),
  ('gate-engineering-mathematics-linear-algebra-q01', 'gate-engineering-mathematics-linear-algebra', 'A square matrix A is invertible if and only if:', 'det(A) = 0', 'trace(A) = 0', 'A is symmetric', 'det(A) ≠ 0', 'D', 'A matrix is non-singular (invertible) exactly when its determinant is non-zero.', 0),
  ('gate-engineering-mathematics-linear-algebra-q02', 'gate-engineering-mathematics-linear-algebra', 'The sum of the eigenvalues of a matrix equals its:', 'Determinant', 'Trace', 'Rank', 'Norm', 'B', 'The sum of eigenvalues equals the trace; their product equals the determinant.', 1),
  ('gate-engineering-mathematics-linear-algebra-q03', 'gate-engineering-mathematics-linear-algebra', 'If the eigenvalues of A are 2 and 3, the eigenvalues of A⁻¹ are:', '2 and 3', '−2 and −3', '1/2 and 1/3', '4 and 9', 'C', 'Eigenvalues of the inverse are the reciprocals of the original eigenvalues.', 2),
  ('gate-engineering-mathematics-linear-algebra-q04', 'gate-engineering-mathematics-linear-algebra', 'The eigenvalues of a triangular matrix are:', 'Always complex', 'Its diagonal entries', 'Its off-diagonal entries', 'Always zero', 'B', 'For a triangular matrix, the eigenvalues are simply the diagonal elements.', 3),
  ('gate-engineering-mathematics-linear-algebra-q05', 'gate-engineering-mathematics-linear-algebra', 'A real symmetric matrix always has:', 'Zero determinant', 'Complex eigenvalues', 'Real eigenvalues', 'Equal eigenvalues', 'C', 'Real symmetric matrices are guaranteed to have real eigenvalues.', 4),
  ('gate-engineering-mathematics-linear-algebra-q06', 'gate-engineering-mathematics-linear-algebra', 'For the system Ax = b to have a unique solution, the rank must satisfy:', 'rank(A) = rank(A|b) = n', 'rank(A) < n', 'rank(A) ≠ rank(A|b)', 'rank(A) = 0', 'A', 'A unique solution needs the coefficient and augmented ranks to equal the number of unknowns n.', 5),
  ('gate-engineering-mathematics-linear-algebra-q07', 'gate-engineering-mathematics-linear-algebra', 'The Cayley–Hamilton theorem states that every square matrix satisfies its own:', 'Characteristic equation', 'Determinant', 'Trace equation', 'Inverse', 'A', 'Every matrix satisfies its characteristic equation, enabling quick computation of inverses and powers.', 6),
  ('gate-engineering-mathematics-linear-algebra-q08', 'gate-engineering-mathematics-linear-algebra', 'If det(A) = 5 and det(B) = 2 for 3×3 matrices, then det(AB) is:', '7', '0', '25', '10', 'D', 'det(AB) = det(A)·det(B) = 5 × 2 = 10.', 7),
  ('gate-engineering-mathematics-probability-q01', 'gate-engineering-mathematics-probability', 'Two events A and B are independent when:', 'P(A ∩ B) = 0', 'P(A) = P(B)', 'P(A ∩ B) = P(A)·P(B)', 'P(A ∪ B) = 1', 'C', 'Independence means the joint probability equals the product of the individual probabilities.', 0),
  ('gate-engineering-mathematics-probability-q02', 'gate-engineering-mathematics-probability', 'The mean of a binomial distribution with parameters n and p is:', 'np(1−p)', 'n/p', 'p/n', 'np', 'D', 'The binomial mean is np; its variance is np(1−p).', 1),
  ('gate-engineering-mathematics-probability-q03', 'gate-engineering-mathematics-probability', 'For a Poisson distribution, the variance equals:', 'λ', 'λ²', '√λ', '1/λ', 'A', 'A Poisson distribution has mean and variance both equal to λ.', 2),
  ('gate-engineering-mathematics-probability-q04', 'gate-engineering-mathematics-probability', 'The expected value when rolling a single fair six-sided die is:', '3', '3.5', '4', '6', 'B', 'E(X) = (1+2+3+4+5+6)/6 = 21/6 = 3.5.', 3),
  ('gate-engineering-mathematics-probability-q05', 'gate-engineering-mathematics-probability', 'The variance of a random variable is given by:', 'E(X) − E(X²)', 'E(X²) + E(X)', '[E(X)]² − E(X²)', 'E(X²) − [E(X)]²', 'D', 'Var(X) = E(X²) − [E(X)]² by definition.', 4),
  ('gate-engineering-mathematics-probability-q06', 'gate-engineering-mathematics-probability', 'Two fair coins are tossed. The probability of getting exactly one head is:', '1/4', '1/3', '1/2', '3/4', 'C', 'Outcomes HT and TH out of four equally likely give 2/4 = 1/2.', 5),
  ('gate-engineering-mathematics-probability-q07', 'gate-engineering-mathematics-probability', 'Conditional probability P(A|B) is defined as:', 'P(A) · P(B)', 'P(B) / P(A)', 'P(A ∪ B) / P(B)', 'P(A ∩ B) / P(B)', 'D', 'P(A|B) = P(A ∩ B)/P(B), assuming P(B) > 0.', 6),
  ('gate-engineering-mathematics-probability-q08', 'gate-engineering-mathematics-probability', 'Adding a constant b to a random variable X changes its variance by:', '2b', 'No change', 'b', 'b²', 'B', 'Var(X + b) = Var(X); shifting by a constant does not affect variance.', 7),
  ('gate-general-aptitude-ratio-logical-puzzles-q01', 'gate-general-aptitude-ratio-logical-puzzles', 'If A : B = 2 : 3 and B : C = 4 : 5, then A : C is:', '2 : 5', '3 : 4', '5 : 8', '8 : 15', 'D', 'Scale to A : B : C = 8 : 12 : 15, so A : C = 8 : 15.', 0),
  ('gate-general-aptitude-ratio-logical-puzzles-q02', 'gate-general-aptitude-ratio-logical-puzzles', '₹1200 is divided between two people in the ratio 2 : 3. The larger share is:', '₹720', '₹600', '₹800', '₹480', 'A', 'The larger share = (3/5) × 1200 = ₹720.', 1),
  ('gate-general-aptitude-ratio-logical-puzzles-q03', 'gate-general-aptitude-ratio-logical-puzzles', 'The mean proportional between 4 and 16 is:', '8', '6', '10', '12', 'A', 'Mean proportional = √(4 × 16) = √64 = 8.', 2),
  ('gate-general-aptitude-ratio-logical-puzzles-q04', 'gate-general-aptitude-ratio-logical-puzzles', 'A does a job in 10 days and B in 15 days. Working together they finish in:', '5 days', '12 days', '6 days', '8 days', 'C', 'Combined rate = 1/10 + 1/15 = 1/6, so they finish in 6 days.', 3),
  ('gate-general-aptitude-ratio-logical-puzzles-q05', 'gate-general-aptitude-ratio-logical-puzzles', 'Pointing to a photo, a man says, ''She is my mother''s only daughter.'' The photo is of his:', 'Wife', 'Sister', 'Mother', 'Daughter', 'B', 'His mother''s only daughter is his sister.', 4),
  ('gate-general-aptitude-ratio-logical-puzzles-q06', 'gate-general-aptitude-ratio-logical-puzzles', 'A man walks 5 km north, then 3 km east, then 5 km south. How far is he from the start?', '3 km', '5 km', '2 km', '8 km', 'A', 'The north and south cancel, leaving 3 km east of the start.', 5),
  ('gate-general-aptitude-ratio-logical-puzzles-q07', 'gate-general-aptitude-ratio-logical-puzzles', 'In what ratio must rice at ₹30/kg be mixed with rice at ₹40/kg to get a mixture at ₹36/kg?', '3 : 2', '4 : 6', '2 : 3', '6 : 4', 'C', 'By alligation, ratio = (40−36) : (36−30) = 4 : 6 = 2 : 3.', 6),
  ('gate-general-aptitude-ratio-logical-puzzles-q08', 'gate-general-aptitude-ratio-logical-puzzles', 'If 3 men can build a wall in 8 days, how many days will 4 men take (same rate)?', '4 days', '6 days', '8 days', '10 days', 'B', 'Work is constant: 3 × 8 = 4 × d, so d = 24/4 = 6 days.', 7),
  ('gate-core-cs-data-structures-complexity-trees-q01', 'gate-core-cs-data-structures-complexity-trees', 'The average-case time complexity of search in a balanced binary search tree is:', 'O(1)', 'O(log n)', 'O(n)', 'O(n log n)', 'B', 'A balanced BST keeps height at log n, giving O(log n) search.', 0),
  ('gate-core-cs-data-structures-complexity-trees-q02', 'gate-core-cs-data-structures-complexity-trees', 'The maximum number of nodes in a binary tree of height h is:', '2^(h+1) − 1', '2^h', '2^h − 1', 'h²', 'A', 'A full binary tree of height h holds 2^(h+1) − 1 nodes.', 1),
  ('gate-core-cs-data-structures-complexity-trees-q03', 'gate-core-cs-data-structures-complexity-trees', 'Which traversal of a binary search tree visits nodes in sorted order?', 'Preorder', 'Level-order', 'Postorder', 'Inorder', 'D', 'Inorder traversal (L, root, R) of a BST yields keys in ascending order.', 2),
  ('gate-core-cs-data-structures-complexity-trees-q04', 'gate-core-cs-data-structures-complexity-trees', 'The average-case time to search in a hash table is:', 'O(n²)', 'O(1)', 'O(n)', 'O(log n)', 'B', 'With good hashing and few collisions, hash-table search is O(1) on average.', 3),
  ('gate-core-cs-data-structures-complexity-trees-q05', 'gate-core-cs-data-structures-complexity-trees', 'In a binary heap stored in an array, the children of node at index i are at:', 'i−1 and i+1', '2i and 2i+1 (0-indexed)', '2i+1 and 2i+2 (0-indexed)', 'i/2 and 2i', 'C', 'For a 0-indexed array heap, node i has children at 2i+1 and 2i+2.', 4),
  ('gate-core-cs-data-structures-complexity-trees-q06', 'gate-core-cs-data-structures-complexity-trees', 'Which notation describes the tight asymptotic bound of an algorithm?', 'Big-Ω', 'Little-o', 'Big-O', 'Big-Θ', 'D', 'Big-Θ gives a tight bound, sandwiching the function between O and Ω.', 5),
  ('gate-core-cs-data-structures-complexity-trees-q07', 'gate-core-cs-data-structures-complexity-trees', 'Searching an unsorted array of n elements has worst-case complexity:', 'O(n)', 'O(log n)', 'O(1)', 'O(n²)', 'A', 'A linear scan may inspect all n elements, giving O(n).', 6),
  ('gate-core-cs-data-structures-complexity-trees-q08', 'gate-core-cs-data-structures-complexity-trees', 'A binary search tree degrades to O(n) operations when it is:', 'Perfectly balanced', 'Completely skewed', 'Empty', 'Complete', 'B', 'A fully skewed BST behaves like a linked list, making operations O(n).', 7),
  ('gate-engineering-mathematics-calculus-q01', 'gate-engineering-mathematics-calculus', 'The derivative of x raised to the power n with respect to x is:', 'x raised to (n plus 1) over (n plus 1)', 'x raised to (n minus 1)', 'n times x raised to n', 'n times x raised to (n minus 1)', 'D', 'By the power rule, d/dx of x^n equals n times x^(n-1).', 0),
  ('gate-engineering-mathematics-calculus-q02', 'gate-engineering-mathematics-calculus', 'At a local minimum of a twice-differentiable function, the second derivative is:', 'Zero', 'Positive', 'Negative', 'Undefined', 'B', 'A positive second derivative at a stationary point indicates a local minimum.', 1),
  ('gate-engineering-mathematics-calculus-q03', 'gate-engineering-mathematics-calculus', 'The value of the integral of cos x with respect to x is:', 'Negative sin x plus C', 'sin x plus C', 'tan x plus C', 'Negative cos x plus C', 'B', 'The antiderivative of cos x is sin x plus a constant.', 2),
  ('gate-engineering-mathematics-calculus-q04', 'gate-engineering-mathematics-calculus', 'The limit of (sin x)/x as x approaches 0 is:', '0', 'Infinity', '1', 'Undefined', 'C', 'This standard limit equals 1, often confirmed via L''Hopital''s rule.', 3),
  ('gate-engineering-mathematics-calculus-q05', 'gate-engineering-mathematics-calculus', 'L''Hopital''s rule applies directly to limits of the indeterminate form:', '0 over 0', '1 over 0', '0 times 1', '1 plus 1', 'A', 'L''Hopital''s rule resolves 0/0 and infinity/infinity indeterminate forms.', 4),
  ('gate-engineering-mathematics-calculus-q06', 'gate-engineering-mathematics-calculus', 'A function is continuous at a point when its left limit, right limit, and function value are:', 'Strictly increasing', 'All zero', 'All equal', 'Undefined', 'C', 'Continuity requires the two one-sided limits and the function value to coincide.', 5),
  ('gate-engineering-mathematics-calculus-q07', 'gate-engineering-mathematics-calculus', 'The definite integral of 2x from 0 to 3 evaluates to:', '6', '3', '9', '12', 'C', 'The integral of 2x is x squared; evaluated from 0 to 3 gives 9 minus 0.', 6),
  ('gate-engineering-mathematics-calculus-q08', 'gate-engineering-mathematics-calculus', 'The Mean Value Theorem guarantees a point where the tangent slope equals the:', 'Average rate of change over the interval', 'Second derivative', 'Maximum value', 'Area under the curve', 'A', 'The MVT gives a point whose instantaneous slope equals the interval''s average rate.', 7),
  ('gate-engineering-mathematics-differential-equations-q01', 'gate-engineering-mathematics-differential-equations', 'The order of a differential equation is determined by its:', 'Highest power of the function', 'Number of terms', 'Degree of the lowest derivative', 'Highest derivative present', 'D', 'Order is the highest derivative appearing in the equation.', 0),
  ('gate-engineering-mathematics-differential-equations-q02', 'gate-engineering-mathematics-differential-equations', 'For the linear equation dy/dx plus P(x)y equals Q(x), the integrating factor is:', 'e raised to the integral of P(x) dx', 'e raised to the integral of Q(x) dx', 'the integral of P(x) dx', 'P(x) times Q(x)', 'A', 'The integrating factor is e raised to the integral of P(x) with respect to x.', 1),
  ('gate-engineering-mathematics-differential-equations-q03', 'gate-engineering-mathematics-differential-equations', 'The auxiliary equation of y double-prime minus 5y prime plus 6y equals 0 has roots:', '2 and 3', '1 and 6', 'Negative 2 and negative 3', '5 and 6', 'A', 'Solving m squared minus 5m plus 6 equals 0 gives m equal to 2 and 3.', 2),
  ('gate-engineering-mathematics-differential-equations-q04', 'gate-engineering-mathematics-differential-equations', 'When the auxiliary equation has a repeated real root m, the general solution form is:', 'C1 plus C2 times x', 'Two distinct exponentials', 'A sine and cosine combination', '(C1 plus C2 x) times e raised to m x', 'D', 'A repeated root m gives the solution (C1 plus C2 x) times e^(m x).', 3),
  ('gate-engineering-mathematics-differential-equations-q05', 'gate-engineering-mathematics-differential-equations', 'A first-order equation M dx plus N dy equals 0 is exact when:', 'M equals N', 'partial M over partial y equals partial N over partial x', 'M times N equals 0', 'partial M over partial x equals partial N over partial y', 'B', 'Exactness requires the partial of M w.r.t. y to equal the partial of N w.r.t. x.', 4),
  ('gate-engineering-mathematics-differential-equations-q06', 'gate-engineering-mathematics-differential-equations', 'The complete solution of a linear differential equation is the sum of the complementary function and the:', 'Integrating factor', 'Boundary value', 'Auxiliary equation', 'Particular integral', 'D', 'General solution equals complementary function plus particular integral.', 5),
  ('gate-engineering-mathematics-differential-equations-q07', 'gate-engineering-mathematics-differential-equations', 'A complex root pair p plus or minus qi of the auxiliary equation yields solutions involving:', 'Polynomials only', 'Logarithms', 'Hyperbolic functions', 'Sine and cosine of qx', 'D', 'Complex roots give e^(p x) times a combination of cos qx and sin qx.', 6),
  ('gate-engineering-mathematics-differential-equations-q08', 'gate-engineering-mathematics-differential-equations', 'A second-order differential equation requires how many independent conditions to fix constants?', 'One', 'Zero', 'Three', 'Two', 'D', 'An order-n equation needs n independent initial or boundary conditions.', 7),
  ('gate-engineering-mathematics-sets-relations-q01', 'gate-engineering-mathematics-sets-relations', 'The number of subsets of a set with 4 elements is:', '16', '8', '4', '32', 'A', 'A set of n elements has 2 raised to n subsets; 2 to the 4th is 16.', 0),
  ('gate-engineering-mathematics-sets-relations-q02', 'gate-engineering-mathematics-sets-relations', 'A relation that is reflexive, symmetric, and transitive is called:', 'A partial order', 'A function', 'A bijection', 'An equivalence relation', 'D', 'These three properties together define an equivalence relation.', 1),
  ('gate-engineering-mathematics-sets-relations-q03', 'gate-engineering-mathematics-sets-relations', 'If set A has m elements and set B has n elements, the number of functions from A to B is:', 'm times n', 'm raised to n', 'n raised to m', 'n factorial', 'C', 'Each of the m elements maps to any of n images, giving n raised to m.', 2),
  ('gate-engineering-mathematics-sets-relations-q04', 'gate-engineering-mathematics-sets-relations', 'A relation is antisymmetric when (a, b) and (b, a) both in R imply:', 'R is empty', 'a is not equal to b', 'a equals b', 'R is reflexive', 'C', 'Antisymmetry forces a to equal b whenever both ordered pairs are present.', 3),
  ('gate-engineering-mathematics-sets-relations-q05', 'gate-engineering-mathematics-sets-relations', 'By inclusion-exclusion, the cardinality of A union B equals:', 'Cardinality of A plus cardinality of B', 'Cardinality of A plus B minus their intersection', 'Cardinality of the intersection only', 'Cardinality of A times cardinality of B', 'B', 'The size of A union B is the sum of sizes minus the size of the intersection.', 4),
  ('gate-engineering-mathematics-sets-relations-q06', 'gate-engineering-mathematics-sets-relations', 'A function that is both injective and surjective is called:', 'Constant', 'Bijective', 'Partial', 'Reflexive', 'B', 'A one-to-one and onto function is a bijection.', 5),
  ('gate-engineering-mathematics-sets-relations-q07', 'gate-engineering-mathematics-sets-relations', 'The total number of binary relations on a set with 3 elements is:', '8', '64', '27', '512', 'D', 'Relations on an n-set number 2 raised to n squared; for n equal 3 that is 2 to the 9, or 512.', 6),
  ('gate-engineering-mathematics-sets-relations-q08', 'gate-engineering-mathematics-sets-relations', 'A partial order relation is reflexive, transitive, and:', 'Symmetric', 'Irreflexive', 'Antisymmetric', 'Surjective', 'C', 'A partial order is reflexive, antisymmetric, and transitive.', 7),
  ('gate-engineering-mathematics-graph-theory-q01', 'gate-engineering-mathematics-graph-theory', 'By the handshaking lemma, the sum of all vertex degrees in a graph equals:', 'Twice the number of edges', 'The number of vertices', 'The number of edges', 'Half the number of edges', 'A', 'Each edge contributes 2 to the total degree, so the sum is twice the edge count.', 0),
  ('gate-engineering-mathematics-graph-theory-q02', 'gate-engineering-mathematics-graph-theory', 'The number of edges in a complete graph on n vertices is:', 'n minus 1', 'n squared', 'n times (n minus 1) over 2', '2 times n', 'C', 'A complete graph K_n has n(n-1)/2 edges, one between every vertex pair.', 1),
  ('gate-engineering-mathematics-graph-theory-q03', 'gate-engineering-mathematics-graph-theory', 'A tree with n vertices has exactly how many edges?', 'n', 'n plus 1', 'n minus 1', '2n minus 1', 'C', 'A tree is connected and acyclic, which forces exactly n minus 1 edges.', 2),
  ('gate-engineering-mathematics-graph-theory-q04', 'gate-engineering-mathematics-graph-theory', 'A connected graph has an Euler circuit if and only if every vertex has:', 'Degree 1', 'Odd degree', 'Even degree', 'Degree 0', 'C', 'An Euler circuit exists when the graph is connected and all degrees are even.', 3),
  ('gate-engineering-mathematics-graph-theory-q05', 'gate-engineering-mathematics-graph-theory', 'For a connected planar graph, Euler''s formula V minus E plus F equals:', '0', '1', '2', 'The number of vertices', 'C', 'Euler''s formula for a connected planar graph states V minus E plus F equals 2.', 4),
  ('gate-engineering-mathematics-graph-theory-q06', 'gate-engineering-mathematics-graph-theory', 'The number of edges in the complete bipartite graph K(3,4) is:', '7', '9', '16', '12', 'D', 'K(m,n) has m times n edges, so K(3,4) has 3 times 4, which is 12.', 5),
  ('gate-engineering-mathematics-graph-theory-q07', 'gate-engineering-mathematics-graph-theory', 'A cycle that visits every vertex exactly once is called a:', 'Hamiltonian cycle', 'Spanning tree', 'Bipartite path', 'Euler circuit', 'A', 'A Hamiltonian cycle passes through every vertex exactly once.', 6),
  ('gate-engineering-mathematics-graph-theory-q08', 'gate-engineering-mathematics-graph-theory', 'The minimum number of colors needed for a proper vertex coloring is the graph''s:', 'Degree', 'Order', 'Chromatic number', 'Girth', 'C', 'The chromatic number is the least number of colors for a proper coloring.', 7),
  ('gate-engineering-mathematics-combinatorics-q01', 'gate-engineering-mathematics-combinatorics', 'The number of ways to choose 2 items from 5 distinct items (order ignored) is:', '10', '20', '25', '120', 'A', '5 choose 2 equals 5 factorial over (2 factorial times 3 factorial), which is 10.', 0),
  ('gate-engineering-mathematics-combinatorics-q02', 'gate-engineering-mathematics-combinatorics', 'The number of distinct arrangements of all letters of the word LEVEL is:', '120', '60', '24', '30', 'D', 'LEVEL has 5 letters with L and E repeated twice; 5 factorial over (2 times 2) is 30.', 1),
  ('gate-engineering-mathematics-combinatorics-q03', 'gate-engineering-mathematics-combinatorics', 'The sum of all binomial coefficients in the expansion of (x plus y) raised to n is:', 'n squared', 'n factorial', '2 raised to n', '2n', 'C', 'Setting x equal y equal 1 shows the coefficients sum to 2 raised to n.', 2),
  ('gate-engineering-mathematics-combinatorics-q04', 'gate-engineering-mathematics-combinatorics', 'The number of circular permutations of 5 distinct objects is:', '120', '24', '20', '60', 'B', 'Circular permutations of n objects number (n minus 1) factorial, so 4 factorial is 24.', 3),
  ('gate-engineering-mathematics-combinatorics-q05', 'gate-engineering-mathematics-combinatorics', 'The pigeonhole principle guarantees that placing 10 items into 9 boxes forces:', 'One empty box', 'Equal distribution', 'At least one box with two items', 'No box with more than one item', 'C', 'With more items than boxes, at least one box must hold two or more items.', 4),
  ('gate-engineering-mathematics-combinatorics-q06', 'gate-engineering-mathematics-combinatorics', 'The number of ways to arrange 3 distinct books on a shelf is:', '6', '9', '12', '3', 'A', 'Arrangements of 3 distinct items equal 3 factorial, which is 6.', 5),
  ('gate-engineering-mathematics-combinatorics-q07', 'gate-engineering-mathematics-combinatorics', 'The identity n choose r equals n choose (n minus r) reflects:', 'Symmetry of combinations', 'The product rule', 'Circular permutation', 'The pigeonhole principle', 'A', 'Choosing r to include is the same as choosing n minus r to exclude.', 6),
  ('gate-engineering-mathematics-combinatorics-q08', 'gate-engineering-mathematics-combinatorics', 'How many distinct 3-digit numbers can be formed using digits 1 to 5 without repetition?', '60', '15', '20', '125', 'A', 'This is 5 permute 3, equal to 5 times 4 times 3, which is 60.', 7),
  ('gate-engineering-mathematics-numerical-methods-q01', 'gate-engineering-mathematics-numerical-methods', 'The Newton-Raphson method has which order of convergence near a simple root?', 'Quadratic', 'Logarithmic', 'Cubic', 'Linear', 'A', 'Newton-Raphson converges quadratically near a simple root.', 0),
  ('gate-engineering-mathematics-numerical-methods-q02', 'gate-engineering-mathematics-numerical-methods', 'The bisection method is guaranteed to converge provided the function:', 'Is differentiable everywhere', 'Has a zero derivative', 'Changes sign over the bracketing interval', 'Is a polynomial', 'C', 'Bisection needs a sign change across the interval to bracket a root.', 1),
  ('gate-engineering-mathematics-numerical-methods-q03', 'gate-engineering-mathematics-numerical-methods', 'Simpson''s one-third rule requires the number of subintervals to be:', 'Odd', 'Even', 'A power of two', 'Prime', 'B', 'Simpson''s one-third rule needs an even number of subintervals.', 2),
  ('gate-engineering-mathematics-numerical-methods-q04', 'gate-engineering-mathematics-numerical-methods', 'The trapezoidal rule has a truncation error of order:', 'h cubed', 'h', 'h to the fourth', 'h squared', 'D', 'The trapezoidal rule has error of order h squared.', 3),
  ('gate-engineering-mathematics-numerical-methods-q05', 'gate-engineering-mathematics-numerical-methods', 'The Newton-Raphson iteration may fail when the derivative at the current point is:', 'Negative', 'Close to zero', 'Large', 'Constant', 'B', 'A near-zero derivative makes the tangent step blow up, causing divergence.', 4),
  ('gate-engineering-mathematics-numerical-methods-q06', 'gate-engineering-mathematics-numerical-methods', 'A unique interpolating polynomial through n plus 1 distinct points has degree at most:', 'n', '2n', 'n minus 1', 'n plus 1', 'A', 'n plus 1 points determine a unique polynomial of degree at most n.', 5),
  ('gate-engineering-mathematics-numerical-methods-q07', 'gate-engineering-mathematics-numerical-methods', 'The secant method differs from Newton-Raphson by:', 'Requiring the exact derivative', 'Always halving the interval', 'Using a fixed step size', 'Approximating the derivative with a difference quotient', 'D', 'The secant method replaces the derivative with a finite difference of two points.', 6),
  ('gate-engineering-mathematics-numerical-methods-q08', 'gate-engineering-mathematics-numerical-methods', 'Reducing the step size h in numerical integration generally lowers truncation error but raises:', 'The order of the method', 'The polynomial degree', 'The number of roots', 'Round-off error', 'D', 'Smaller h cuts truncation error but accumulates more round-off error.', 7),
  ('gate-general-aptitude-quantitative-aptitude-q01', 'gate-general-aptitude-quantitative-aptitude', 'A 20 percent increase followed by a 20 percent decrease results in a net:', '4 percent increase', '4 percent decrease', 'No change', '20 percent decrease', 'B', 'Net factor is 1.2 times 0.8, equal 0.96, which is a 4 percent decrease.', 0),
  ('gate-general-aptitude-quantitative-aptitude-q02', 'gate-general-aptitude-quantitative-aptitude', 'The simple interest on 1000 rupees at 5 percent per year for 2 years is:', '150 rupees', '50 rupees', '100 rupees', '200 rupees', 'C', 'Simple interest is principal times rate times time over 100, giving 100 rupees.', 1),
  ('gate-general-aptitude-quantitative-aptitude-q03', 'gate-general-aptitude-quantitative-aptitude', 'An item bought for 80 rupees and sold for 100 rupees gives a profit percentage of:', '20 percent', '15 percent', '30 percent', '25 percent', 'D', 'Profit is 20 on a cost of 80, so profit percent is 20 over 80, which is 25.', 2),
  ('gate-general-aptitude-quantitative-aptitude-q04', 'gate-general-aptitude-quantitative-aptitude', 'A train travels 120 km in 2 hours. Its average speed is:', '60 km per hour', '40 km per hour', '50 km per hour', '80 km per hour', 'A', 'Average speed is distance over time, 120 divided by 2, equal 60 km per hour.', 3),
  ('gate-general-aptitude-quantitative-aptitude-q05', 'gate-general-aptitude-quantitative-aptitude', 'The average of 10, 20, and 30 is:', '15', '25', '30', '20', 'D', 'The average is the sum 60 divided by 3, which is 20.', 4),
  ('gate-general-aptitude-quantitative-aptitude-q06', 'gate-general-aptitude-quantitative-aptitude', 'Two trains move toward each other at 40 and 60 km per hour. Their relative speed is:', '100 km per hour', '50 km per hour', '20 km per hour', '10 km per hour', 'A', 'For opposite directions, relative speed is the sum, 40 plus 60, which is 100.', 5),
  ('gate-general-aptitude-quantitative-aptitude-q07', 'gate-general-aptitude-quantitative-aptitude', 'If the compound interest rate is 10 percent per year, 100 rupees grows in 2 years to:', '110 rupees', '120 rupees', '121 rupees', '125 rupees', 'C', 'Amount is 100 times 1.1 squared, equal 121 rupees.', 6),
  ('gate-general-aptitude-quantitative-aptitude-q08', 'gate-general-aptitude-quantitative-aptitude', 'What is 15 percent of 200?', '20', '15', '45', '30', 'D', '15 percent of 200 is 0.15 times 200, which equals 30.', 7),
  ('gate-general-aptitude-verbal-ability-q01', 'gate-general-aptitude-verbal-ability', 'Choose the word most nearly opposite in meaning to ABUNDANT:', 'Scarce', 'Numerous', 'Ample', 'Plentiful', 'A', 'Abundant means plentiful, so its antonym is scarce.', 0),
  ('gate-general-aptitude-verbal-ability-q02', 'gate-general-aptitude-verbal-ability', 'Select the correct sentence:', 'She do not like coffee.', 'She does not likes coffee.', 'She not like coffee.', 'She does not like coffee.', 'D', 'The auxiliary does pairs with the base verb like in the negative present tense.', 1),
  ('gate-general-aptitude-verbal-ability-q03', 'gate-general-aptitude-verbal-ability', 'Choose a synonym for METICULOUS:', 'Vague', 'Hasty', 'Careful', 'Careless', 'C', 'Meticulous means showing great care and attention, so careful is a synonym.', 2),
  ('gate-general-aptitude-verbal-ability-q04', 'gate-general-aptitude-verbal-ability', 'The article that correctly fills the blank in the phrase a blank hour of waiting is:', 'the, in all cases', 'a, because hour begins with a consonant letter', 'an, because hour begins with a vowel sound', 'no article is needed', 'C', 'Hour starts with a silent h and a vowel sound, so an is correct.', 3),
  ('gate-general-aptitude-verbal-ability-q05', 'gate-general-aptitude-verbal-ability', 'Complete the analogy: PEN is to WRITE as KNIFE is to:', 'Sharp', 'Kitchen', 'Cut', 'Metal', 'C', 'A pen is used to write, as a knife is used to cut.', 4),
  ('gate-general-aptitude-verbal-ability-q06', 'gate-general-aptitude-verbal-ability', 'Choose the correctly spelled word:', 'Definitely', 'Definitly', 'Defenitely', 'Definately', 'A', 'The correct spelling is definitely.', 5),
  ('gate-general-aptitude-verbal-ability-q07', 'gate-general-aptitude-verbal-ability', 'Select the word that correctly fills the blank: The decision will blank the outcome of the project.', 'affect', 'affective', 'effect', 'effecting', 'A', 'Affect is the verb meaning to influence; effect is usually a noun here.', 6),
  ('gate-general-aptitude-verbal-ability-q08', 'gate-general-aptitude-verbal-ability', 'In reading comprehension, an inference is best described as:', 'A directly stated fact', 'A quoted sentence', 'A conclusion drawn from given information', 'The title of the passage', 'C', 'An inference is a logical conclusion derived from, but not directly stated in, the text.', 7),
  ('gate-general-aptitude-data-interpretation-q01', 'gate-general-aptitude-data-interpretation', 'In a pie chart, a category representing 25 percent of the total spans how many degrees?', '90 degrees', '45 degrees', '120 degrees', '25 degrees', 'A', '25 percent of 360 degrees is 90 degrees.', 0),
  ('gate-general-aptitude-data-interpretation-q02', 'gate-general-aptitude-data-interpretation', 'Which chart type is best suited for showing a trend over time?', 'Pie chart', 'Scatter of unrelated points', 'Line graph', 'Venn diagram', 'C', 'A line graph clearly displays how a value changes over time.', 1),
  ('gate-general-aptitude-data-interpretation-q03', 'gate-general-aptitude-data-interpretation', 'A value rises from 200 to 250. The percentage increase is:', '25 percent', '10 percent', '50 percent', '20 percent', 'A', 'Increase is 50 over 200, which equals 25 percent.', 2),
  ('gate-general-aptitude-data-interpretation-q04', 'gate-general-aptitude-data-interpretation', 'If a 90 degree sector of a pie chart represents 45 units, the whole pie represents:', '90 units', '135 units', '360 units', '180 units', 'D', '90 degrees is a quarter of the pie, so the total is 4 times 45, which is 180.', 3),
  ('gate-general-aptitude-data-interpretation-q05', 'gate-general-aptitude-data-interpretation', 'The average of the values 40, 60, and 80 shown in a bar chart is:', '50', '80', '70', '60', 'D', 'The average is the sum 180 divided by 3, which is 60.', 4),
  ('gate-general-aptitude-data-interpretation-q06', 'gate-general-aptitude-data-interpretation', 'Before computing from a chart, the first thing to confirm is the:', 'Units and scale of the data', 'Number of categories only', 'Font of the labels', 'Color of the bars', 'A', 'Misreading units or scale, such as thousands versus units, is a common error.', 5),
  ('gate-general-aptitude-data-interpretation-q07', 'gate-general-aptitude-data-interpretation', 'Two categories occupy 120 and 60 degrees of a pie chart. Their value ratio is:', '1 to 1', '2 to 1', '3 to 1', '1 to 2', 'B', 'Angles are proportional to values, so 120 to 60 simplifies to 2 to 1.', 6),
  ('gate-general-aptitude-data-interpretation-q08', 'gate-general-aptitude-data-interpretation', 'Sales were 300 in year one and 240 in year two. The percentage decrease is:', '25 percent', '30 percent', '20 percent', '60 percent', 'C', 'Decrease is 60 over 300, which equals 20 percent.', 7),
  ('gate-general-aptitude-logical-reasoning-series-q01', 'gate-general-aptitude-logical-reasoning-series', 'Find the next term: 2, 4, 8, 16, ?', '32', '20', '24', '30', 'A', 'Each term doubles the previous one, so 16 times 2 is 32.', 0),
  ('gate-general-aptitude-logical-reasoning-series-q02', 'gate-general-aptitude-logical-reasoning-series', 'Find the next term: 1, 4, 9, 16, ?', '20', '25', '24', '36', 'B', 'These are perfect squares, so the next is 5 squared, which is 25.', 1),
  ('gate-general-aptitude-logical-reasoning-series-q03', 'gate-general-aptitude-logical-reasoning-series', 'In a code, CAT is written as DBU. How is DOG written?', 'CPF', 'EPI', 'EPH', 'DPH', 'C', 'Each letter shifts forward by one, so DOG becomes EPH.', 2),
  ('gate-general-aptitude-logical-reasoning-series-q04', 'gate-general-aptitude-logical-reasoning-series', 'Find the next term in the Fibonacci-like series: 1, 1, 2, 3, 5, ?', '6', '7', '8', '10', 'C', 'Each term is the sum of the previous two, so 3 plus 5 is 8.', 3),
  ('gate-general-aptitude-logical-reasoning-series-q05', 'gate-general-aptitude-logical-reasoning-series', 'Find the next term: 2, 6, 12, 20, ?', '24', '28', '32', '30', 'D', 'Terms follow n times (n plus 1); for n equal 5 that is 30.', 4),
  ('gate-general-aptitude-logical-reasoning-series-q06', 'gate-general-aptitude-logical-reasoning-series', 'If all roses are flowers and some flowers fade quickly, which conclusion is valid?', 'Some roses may fade quickly', 'No rose is a flower', 'All roses fade quickly', 'All flowers are roses', 'A', 'Only a possibility follows; no definite conclusion about all roses can be drawn.', 5),
  ('gate-general-aptitude-logical-reasoning-series-q07', 'gate-general-aptitude-logical-reasoning-series', 'By modus tollens, if P implies Q and Q is false, then:', 'P is true', 'Q is true', 'P is false', 'Nothing follows', 'C', 'If P implies Q and Q is false, then P must be false.', 6),
  ('gate-general-aptitude-logical-reasoning-series-q08', 'gate-general-aptitude-logical-reasoning-series', 'Find the missing term: 3, 6, 11, 18, ?', '25', '27', '29', '24', 'B', 'Differences grow as 3, 5, 7, 9, so 18 plus 9 is 27.', 7),
  ('gate-core-cs-algorithms-sorting-complexity-q01', 'gate-core-cs-algorithms-sorting-complexity', 'The worst-case time complexity of quick sort is:', 'O(n squared)', 'O(n log n)', 'O(n)', 'O(log n)', 'A', 'A poor pivot, such as on sorted input, gives quick sort O(n squared) worst case.', 0),
  ('gate-core-cs-algorithms-sorting-complexity-q02', 'gate-core-cs-algorithms-sorting-complexity', 'Which sorting algorithm guarantees O(n log n) time in the worst case and is stable?', 'Quick sort', 'Selection sort', 'Merge sort', 'Heap sort', 'C', 'Merge sort is stable and runs in O(n log n) even in the worst case.', 1),
  ('gate-core-cs-algorithms-sorting-complexity-q03', 'gate-core-cs-algorithms-sorting-complexity', 'The lower bound for any comparison-based sorting algorithm is:', 'Omega(n log n)', 'Omega(log n)', 'Omega(n)', 'Omega(n squared)', 'A', 'Comparison sorts cannot beat Omega(n log n) in the worst case.', 2),
  ('gate-core-cs-algorithms-sorting-complexity-q04', 'gate-core-cs-algorithms-sorting-complexity', 'The recurrence T(n) equals 2 T(n over 2) plus O(n) solves to:', 'O(n)', 'O(n log n)', 'O(n squared)', 'O(log n)', 'B', 'By the master theorem this merge-sort recurrence is O(n log n).', 3),
  ('gate-core-cs-algorithms-sorting-complexity-q05', 'gate-core-cs-algorithms-sorting-complexity', 'Insertion sort runs in O(n) time when the input array is:', 'Reverse sorted', 'All equal except one', 'Randomly shuffled', 'Already sorted', 'D', 'On already-sorted input, insertion sort makes one comparison per element, O(n).', 4),
  ('gate-core-cs-algorithms-sorting-complexity-q06', 'gate-core-cs-algorithms-sorting-complexity', 'Which sort runs in linear time for bounded integer keys by avoiding comparisons?', 'Quick sort', 'Merge sort', 'Counting sort', 'Heap sort', 'C', 'Counting sort uses key values as indices, achieving linear time for bounded keys.', 5),
  ('gate-core-cs-algorithms-sorting-complexity-q07', 'gate-core-cs-algorithms-sorting-complexity', 'Heap sort has an auxiliary space complexity of:', 'O(log n)', 'O(1)', 'O(n)', 'O(n log n)', 'B', 'Heap sort sorts in place, using only O(1) extra space.', 6),
  ('gate-core-cs-algorithms-sorting-complexity-q08', 'gate-core-cs-algorithms-sorting-complexity', 'A sorting algorithm is stable if it:', 'Always runs in O(n log n)', 'Never recurses', 'Uses no extra memory', 'Preserves the relative order of equal keys', 'D', 'Stability means equal keys keep their original relative order after sorting.', 7),
  ('gate-core-cs-greedy-dynamic-programming-q01', 'gate-core-cs-greedy-dynamic-programming', 'Dijkstra''s shortest-path algorithm is an example of which paradigm?', 'Backtracking', 'Divide and conquer', 'Greedy', 'Brute force', 'C', 'Dijkstra greedily selects the nearest unvisited vertex at each step.', 0),
  ('gate-core-cs-greedy-dynamic-programming-q02', 'gate-core-cs-greedy-dynamic-programming', 'Dynamic programming is preferred over plain recursion mainly because it:', 'Avoids all recursion', 'Uses less code', 'Requires no base case', 'Stores results of overlapping subproblems', 'D', 'DP memoizes overlapping subproblems so each is solved only once.', 1),
